#include <iostream>#include <vector>#include <algorithm>#include <cmath>#include <string>#include <map>#include <set>#include <iomanip>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    long long  n,k,x;    cin >> n >> k >> x;    long long mini_possible=k*(k+1)/2;    long long maxi_possible=n * (n + 1) / 2 - (n - k) * (n - k + 1) / 2;        if(mini_possible<=x && x<=maxi_possible){        cout << "YES\n";    }else{        cout << "NO\n";    }        } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}